// A tiny, basic SPA Router
document.body.addEventListener('click', e => {
  if (e.target.matches('a')) {
    e.preventDefault(); // Stop the page reload!

    // 1. Update the URL bar visually
    history.pushState(null, '', e.target.href);

    // 2. Erase the old page and draw the new one
    const contentDiv = document.querySelector('#app');
    if (e.target.href.includes('about')) {
      contentDiv.innerHTML = '<h1>About Us</h1><p>We are a cool company.</p>';
    }
  }
});
